```c
#include <math.h>

// 定义数据类型表示三维坐标
typedef struct {
    double x;
    double y;
    double z;
} Vector3D;

// 计算并返回方位角（弧度）
double calculateHeadingAngle(Vector3D magnetometer, Vector3D accelerometer) {
    // 计算水平面上的方位角
    double heading = atan2(magnetometer.y, magnetometer.x);

    // 调整方位角以考虑倾斜角度
    double roll = atan2(accelerometer.y, accelerometer.z);
    double pitch = atan2(-accelerometer.x, sqrt(accelerometer.y * accelerometer.y + accelerometer.z * accelerometer.z));

    // 考虑倾斜角度对方位角进行校正
    heading += roll;

    // 强制方位角值在0-2π范围内
    if (heading < 0.0) {
        heading += 2.0 * M_PI;
    } else if (heading >= 2.0 * M_PI) {
        heading -= 2.0 * M_PI;
    }

    return heading;
}
```

